d end SWEP.Hook_Think=function(Z)local K=(Z:GetOwner()):GetViewModel()if not IsValid(K)then return end local a=Z:GetOwner()local t=CurTime()if Z.HideLinksAt and t>=Z.HideLinksAt then Z.HiddenLinks=true Z.HideLinksAt=nil end if Z.LastClip1~=Z:Clip1()then Z.HiddenLinks=false Z.LastClip1=Z:Clip1()end D(Z,K)if Z.HideBullet==true then C(Z,K)end if Z:IsJammed()and not Z.JamAnimPlayed then local K=table.Random(Z.JamAnims)Z:PlayAnimation(K.anim)Z.JamAnimPlayed=true end local v=Z:GetHeat()local o=Z:GetOwner()local L=CurTime()if v>=Z.HeatCapacity and not Z.Overheated then Z.Overheated=true Z.OverheatEndTime=L+15 elseif Z.Overheated and L>=Z.OverheatEndTime then Z.Overheated=false end end SWEP.Hook_ModifyBodygroups=function(Z,K)local a=K.vm if not IsValid(a)then return end D(Z,K.vm)if Z.HideBullet==true then C(Z,K.vm)end end function SWEP.IsJammed(Z)return Z.Jammed end function SWEP.JamWeapon(Z)if Z:IsJammed()then return end Z.Jammed=true Z.JamAnimPlayed=false local K=table.Random(Z.JamAnims)local C=K.time Z:PlayAnimation(K.anim)Z:SetNextPrimaryFire(CurTime()+C)timer.Simple(C,function()if IsValid(Z)then Z.Jammed=false Z.JamAnimPlayed=false end end)end SWEP.Hook_PreFireBullets=function(Z)if Z:IsJammed()then return false end if math.random()<Z.JamChance then Z:JamWeapon()return false end end SWEP.Hook_ShouldNotFire=function(Z)if Z:IsJammed()then return true end end
